public static String next_palindrome(int[] digit_list) {
    int mid = digit_list.length / 2;
    int left = mid - 1;
    int right = digit_list.length % 2 == 0 ? mid : mid + 1;
    while (left >= 0 && digit_list[left] == digit_list[right]) {
        digit_list[left]++;
        digit_list[right]++;
        left--;
        right++;
    }
    if (left < 0 || digit_list[left] < digit_list[right]) {
        int carry = 1;
        int i = 0;
        while (i < digit_list.length) {
            int sum = digit_list[i] + carry;
            digit_list[i] = sum % 10;
            carry = sum / 10;
            i++;
        }
        if (carry > 0) {
            int[] new_digit_list = new int[digit_list.length + 1];
            System.arraycopy(digit_list, 0, new_digit_list, 1, digit_list.length);
            new_digit_list[0] = carry;
            digit_list = new_digit_list;
        }
    } else {
        while (right < digit_list.length) {
            digit_list[right] = digit_list[left];
            left--;
            right++;
        }
    }
    return Arrays.toString(digit_list);
}

