            Double a = (Double) stack.pop();
            Double b = (Double) stack.pop();
            Double c = 0.0;
            BinaryOperator<Double> bin_op = op.get(token);
            c = bin_op.apply(a,b);
                        stack.push(c);
        }
    }
    return (Double) stack.pop();
}

